// Parse and validate Hotel Workflow response
const items = $input.all();
const results = [];

for (const item of items) {
  const testData = item.json;
  const httpResponse = testData.body || {};
  const httpStatus = testData.statusCode || 0;

  let parsed = {
    test_id: testData.test_id,
    expected_intent: testData.expected_intent,
    expected_language: testData.expected_language,
    query: testData.query,
    session_id: testData.session_id,
    http_status: httpStatus,
    agent_response: JSON.stringify(httpResponse),
    actual_intent: httpResponse.intent || 'unknown',
    actual_response: httpResponse.response || '',
    actual_session_id: httpResponse.session_id || '',
    reference_id: httpResponse.reference_id || null,
    reservation_submitted: httpResponse.reservation_submitted || false,
    timestamp: new Date().toISOString()
  };

  // Detect language in response (basic detection)
  const detectLanguage = (text) => {
    if (!text) return 'unknown';
    // Portuguese detection
    if (/\b(obrigado|por favor|olá|sim|não|como|que|para)\b/i.test(text)) {
      // Check for Brazilian Portuguese indicators
      if (/\b(você|pra|tá|vocês)\b/i.test(text)) {
        return 'pt-BR';
      }
      return 'pt-PT';
    }
    // English detection
    if (/\b(hello|thank|please|yes|no|how|what|for|the|and)\b/i.test(text)) {
      return 'en';
    }
    // Spanish detection
    if (/\b(hola|gracias|por favor|sí|cómo|qué|para)\b/i.test(text)) {
      return 'es';
    }
    // French detection
    if (/\b(bonjour|merci|s'il vous plaît|oui|non|comment|quoi)\b/i.test(text)) {
      return 'fr';
    }
    return 'en'; // default
  };

  parsed.detected_language = detectLanguage(parsed.actual_response);

  results.push({ json: parsed });
}

return results;

// Calculate Intent Classification Accuracy
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;

  const expected = (data.expected_intent || '').toLowerCase().trim();
  const actual = (data.actual_intent || '').toLowerCase().trim();

  const intentAccuracy = expected === actual ? 1 : 0;

  results.push({
    json: {
      ...data,
      intent_accuracy: intentAccuracy,
      intent_match_details: `Expected: ${expected}, Actual: ${actual}`
    }
  });
}

return results;

// Calculate Language Consistency Score
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;

  const expected = (data.expected_language || '').toLowerCase().trim();
  const detected = (data.detected_language || '').toLowerCase().trim();

  let languageScore = 0;
  let languageNotes = '';

  // Exact match
  if (expected === detected) {
    languageScore = 1;
    languageNotes = 'Language matches exactly';
  } 
  // Special case: pt-PT vs pt-BR
  else if (expected === 'pt-pt' && detected === 'pt-br') {
    languageScore = 0;
    languageNotes = 'CRITICAL: Used Brazilian Portuguese instead of European Portuguese';
  }
  // Base language match (en vs en-US)
  else if (expected.split('-')[0] === detected.split('-')[0]) {
    languageScore = 0.8;
    languageNotes = 'Base language matches, dialect differs';
  }
  // No match
  else {
    languageScore = 0;
    languageNotes = `Language mismatch: expected ${expected}, got ${detected}`;
  }

  results.push({
    json: {
      ...data,
      language_score: languageScore,
      language_notes: languageNotes
    }
  });
}

return results;

// Calculate Reservation Data Completeness
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;

  const intent = (data.actual_intent || '').toLowerCase();
  const isReservationIntent = ['taxi_reservation', 'diner_reservation'].includes(intent);

  let reservationScore = null; // N/A by default
  let reservationNotes = 'Not a reservation intent';

  if (isReservationIntent) {
    const referenceId = data.reference_id;
    const submitted = data.reservation_submitted;

    // Check reference ID format
    const hasValidFormat = referenceId && /^(TAXI|DINER)-\d+-[a-z0-9]+$/i.test(referenceId);

    if (submitted && hasValidFormat) {
      reservationScore = 1;
      reservationNotes = `Valid reservation: ${referenceId}`;
    } else if (!submitted) {
      reservationScore = 0.5;
      reservationNotes = 'Collecting information (multi-turn in progress)';
    } else if (!hasValidFormat) {
      reservationScore = 0;
      reservationNotes = 'Invalid or missing reference ID format';
    }
  }

  results.push({
    json: {
      ...data,
      reservation_score: reservationScore,
      reservation_notes: reservationNotes
    }
  });
}

return results;

// Calculate Error Handling Score
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;

  const httpStatus = data.http_status || 0;
  const response = (data.actual_response || '').toLowerCase();

  let errorScore = null; // N/A by default
  let errorNotes = 'Not an error test';

  // Check if this was an error scenario (5xx, timeout, etc.)
  if (httpStatus >= 500 || httpStatus === 0) {
    // Error occurred - check for graceful handling
    if (response.includes('technical difficulties') || 
        response.includes('experiencing issues') ||
        response.includes('try again') ||
        response.includes('apologize')) {
      errorScore = 1;
      errorNotes = 'Graceful error message provided';
    } else {
      errorScore = 0;
      errorNotes = 'Poor error handling or exposed technical details';
    }
  }
  // Check for error messages in 200 responses (shouldn't happen)
  else if (httpStatus === 200 && 
           (response.includes('error:') || 
            response.includes('exception') ||
            response.includes('stack trace'))) {
    errorScore = 0;
    errorNotes = 'Technical error details exposed to user';
  }

  results.push({
    json: {
      ...data,
      error_handling: errorScore,
      error_notes: errorNotes
    }
  });
}

return results;

// Aggregate all metrics with weighted scoring
const items = $input.all();
const results = [];

// Weights
const WEIGHTS = {
  intent_accuracy: 0.40,
  response_quality: 0.30,
  language_score: 0.15,
  reservation_score: 0.10,
  error_handling: 0.05
};

for (const item of items) {
  const data = item.json;

  // Normalize response quality from 1-5 scale to 0-1
  const responseQuality = data['Response Quality'] || data.response_quality || 3;
  const normalizedQuality = (responseQuality - 1) / 4; // Convert 1-5 to 0-1

  // Collect all scores
  const scores = {
    intent_accuracy: data.intent_accuracy || 0,
    response_quality: normalizedQuality,
    language_score: data.language_score !== null ? data.language_score : 1,
    reservation_score: data.reservation_score,
    error_handling: data.error_handling
  };

  // Calculate weighted score (only for applicable metrics)
  let totalWeight = 0;
  let weightedSum = 0;

  for (const [metric, weight] of Object.entries(WEIGHTS)) {
    if (scores[metric] !== null && scores[metric] !== undefined) {
      weightedSum += scores[metric] * weight;
      totalWeight += weight;
    }
  }

  const finalScore = totalWeight > 0 ? weightedSum / totalWeight : 0;

  // Determine pass/fail (threshold: 0.7 = 70%)
  const passed = finalScore >= 0.7;

  // Count checks
  let checksPassed = 0;
  let checksFailed = 0;
  let checksWarnings = 0;

  if (scores.intent_accuracy === 1) checksPassed++; else checksFailed++;
  if (scores.response_quality >= 0.6) checksPassed++; else if (scores.response_quality >= 0.4) checksWarnings++; else checksFailed++;
  if (scores.language_score === 1) checksPassed++; else if (scores.language_score >= 0.8) checksWarnings++; else if (scores.language_score !== null) checksFailed++;
  if (scores.reservation_score === 1) checksPassed++; else if (scores.reservation_score === 0.5) checksWarnings++; else if (scores.reservation_score === 0) checksFailed++;
  if (scores.error_handling === 1) checksPassed++; else if (scores.error_handling === 0) checksFailed++;

  // Build scoring notes
  const notes = [
    `Intent Accuracy: ${(scores.intent_accuracy * 100).toFixed(0)}% (weight: ${(WEIGHTS.intent_accuracy * 100)}%)`,
    `Response Quality: ${(scores.response_quality * 100).toFixed(0)}% (weight: ${(WEIGHTS.response_quality * 100)}%)`,
    `Language Score: ${scores.language_score !== null ? (scores.language_score * 100).toFixed(0) + '%' : 'N/A'} (weight: ${(WEIGHTS.language_score * 100)}%)`,
    `Reservation Score: ${scores.reservation_score !== null ? (scores.reservation_score * 100).toFixed(0) + '%' : 'N/A'} (weight: ${(WEIGHTS.reservation_score * 100)}%)`,
    `Error Handling: ${scores.error_handling !== null ? (scores.error_handling * 100).toFixed(0) + '%' : 'N/A'} (weight: ${(WEIGHTS.error_handling * 100)}%)`,
    `---`,
    `Final Score: ${(finalScore * 100).toFixed(1)}%`,
    `Status: ${passed ? 'PASSED' : 'FAILED'}`,
    `Details: ${data.intent_match_details || ''}, ${data.language_notes || ''}, ${data.reservation_notes || ''}, ${data.error_notes || ''}`
  ];

  results.push({
    json: {
      ...data,
      score: parseFloat(finalScore.toFixed(3)),
      passed: passed,
      checks_passed: checksPassed,
      checks_failed: checksFailed,
      checks_warnings: checksWarnings,
      scoring_notes: notes.join('\n'),
      evaluated_at: new Date().toISOString()
    }
  });
}

return results;
